using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<ShipmentEntity> Shipments => Set<ShipmentEntity>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<ShipmentEntity>(e =>
        {
            e.HasIndex(s => s.TrackingNumber).IsUnique();
        });

        builder.Entity<ShipmentEntity>().HasData(
            new ShipmentEntity { Id = 1, TrackingNumber = "TRK-001", Origin = "New York, US", Destination = "London, UK", Status = ShipmentStatus.InTransit, EstimatedDelivery = new DateTime(2026, 6, 1), CustomerEmail = "alice@example.com", Description = "Electronics - 2 boxes", CreatedAt = new DateTime(2026, 5, 20) },
            new ShipmentEntity { Id = 2, TrackingNumber = "TRK-002", Origin = "Shanghai, CN", Destination = "Los Angeles, US", Status = ShipmentStatus.OutForDelivery, EstimatedDelivery = new DateTime(2026, 5, 24), CustomerEmail = "bob@example.com", Description = "Furniture - 1 pallet", CreatedAt = new DateTime(2026, 5, 10) },
            new ShipmentEntity { Id = 3, TrackingNumber = "TRK-003", Origin = "Berlin, DE", Destination = "Tokyo, JP", Status = ShipmentStatus.Pending, EstimatedDelivery = new DateTime(2026, 6, 10), CustomerEmail = "carol@example.com", Description = "Auto parts - 5 crates", CreatedAt = new DateTime(2026, 5, 22) },
            new ShipmentEntity { Id = 4, TrackingNumber = "TRK-004", Origin = "Sydney, AU", Destination = "Dubai, AE", Status = ShipmentStatus.Delivered, EstimatedDelivery = new DateTime(2026, 5, 18), CustomerEmail = "dave@example.com", Description = "Clothing - 3 boxes", CreatedAt = new DateTime(2026, 5, 5) },
            new ShipmentEntity { Id = 5, TrackingNumber = "TRK-005", Origin = "São Paulo, BR", Destination = "Miami, US", Status = ShipmentStatus.Delayed, EstimatedDelivery = new DateTime(2026, 5, 28), CustomerEmail = "eve@example.com", Description = "Perishable goods - refrigerated", CreatedAt = new DateTime(2026, 5, 15) }
        );
    }
}

