// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

// Shipment API endpoints
var shipments = app.MapGroup("api/shipments").RequireAuthorization();

shipments.MapGet("", async (ApplicationDbContext db) =>
{
    return await db.Shipments.OrderByDescending(s => s.CreatedAt).Select(e => new Shipment
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Origin = e.Origin,
        Destination = e.Destination,
        Status = e.Status,
        EstimatedDelivery = e.EstimatedDelivery,
        CustomerEmail = e.CustomerEmail,
        Description = e.Description,
        CreatedAt = e.CreatedAt
    }).ToListAsync();
}).RequireAuthorization("DispatcherPolicy");

shipments.MapGet("track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
{
    var entity = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    if (entity is null) return Results.NotFound();
    return Results.Ok(new Shipment
    {
        Id = entity.Id,
        TrackingNumber = entity.TrackingNumber,
        Origin = entity.Origin,
        Destination = entity.Destination,
        Status = entity.Status,
        EstimatedDelivery = entity.EstimatedDelivery,
        CustomerEmail = entity.CustomerEmail,
        Description = entity.Description,
        CreatedAt = entity.CreatedAt
    });
});

shipments.MapPut("{id}/status", async (int id, ShipmentStatus newStatus, ApplicationDbContext db) =>
{
    var entity = await db.Shipments.FindAsync(id);
    if (entity is null) return Results.NotFound();
    entity.Status = newStatus;
    await db.SaveChangesAsync();
    return Results.Ok(new Shipment
    {
        Id = entity.Id,
        TrackingNumber = entity.TrackingNumber,
        Origin = entity.Origin,
        Destination = entity.Destination,
        Status = entity.Status,
        EstimatedDelivery = entity.EstimatedDelivery,
        CustomerEmail = entity.CustomerEmail,
        Description = entity.Description,
        CreatedAt = entity.CreatedAt
    });
}).RequireAuthorization("DispatcherPolicy");

app.Run();

